"experimental.chat.messages.transform": async (input, output) => {
  const sessionID = (input as any).sessionID || output.messages[0]?.info.sessionID || 'default'
  const idVisibility = getIdVisibility(sessionID)

  // Convert to WithParts format for transform
  const messages = convertPluginMessages(output.messages)

  // Debug logging
  const beforeCount = messages.length
  const archivesBefore = messages.filter(m => {
    const archive = (m.metadata[PLUGIN_ID] as any)?.archive
    return archive !== undefined
  }).map(m => ({ id: m.id, archive: (m.metadata[PLUGIN_ID] as any)?.archive }))

  console.log('[TRANSFORM] Before:', { 
    messageCount: beforeCount, 
    archives: archivesBefore,
    idVisibility 
  })

  transformMessages(messages, PLUGIN_ID, idVisibility, sessionID)

  // Debug logging after transform
  const afterCount = messages.length
  console.log('[TRANSFORM] After:', { 
    messageCount: afterCount,
    removed: beforeCount - afterCount,
    firstFewMessages: messages.slice(0, 3).map(m => ({
      id: m.id,
      role: m.role,
