const toIndex = findMessageIndex(messages, args.to_id)!

// Write archive metadata and replace parts in the anchor message
await (ctx as any).updateMessage(args.from_id, (draft: any) => {
  if (!draft.metadata) draft.metadata = {}
  draft.metadata[PLUGIN_ID] = {
    archive: {
      summary: args.summary,
      indexTerms: args.index_terms,
      rangeEnd: args.to_id
    }
  }

  // Replace message parts with placeholder
  const placeholderText = `[PRUNED: ${args.from_id} to ${args.to_id}]\nSummary: ${args.summary}\nIndex: ${args.index_terms.join(', ')}`
  draft.parts = [{
    type: 'text',
    text: placeholderText,
    synthetic: true
  }]
})

// Remove follower messages if range spans multiple messages
if (fromIndex !== toIndex) {
  for (let i = fromIndex + 1; i <= toIndex; i++) {
    const msgId = messages[i].id
    await (ctx as any).updateMessage(msgId, (draft: any) => {
      draft.parts = []
    })
  }
}

